use gnosis_rtl_bridge::ir::SieveFsmIrV0;
use gnosis_rtl_bridge::lift_outcome;
use serde::Deserialize;

#[derive(Debug, Deserialize)]
struct FileRoot {
    vectors: Vec<Vector>,
}

#[derive(Debug, Deserialize)]
struct Vector {
    label: String,
    heads: u16,
    coupling: u16,
    observer_resolution: u16,
    residue_threshold: u16,
    expect_lift: bool,
    expect_after_observer_resolution: u16,
}

#[test]
fn golden_json_matches_reference_model() {
    let raw = include_str!("golden_lift_vectors.json");
    let parsed: FileRoot = serde_json::from_str(raw).expect("parse golden json");
    for v in &parsed.vectors {
        let ir = SieveFsmIrV0::new(
            v.heads,
            v.coupling,
            v.observer_resolution,
            v.residue_threshold,
        );
        let o = lift_outcome(&ir);
        assert_eq!(o.lift, v.expect_lift, "lift mismatch for {}", v.label);
        assert_eq!(
            o.after_observer_resolution, v.expect_after_observer_resolution,
            "after observer mismatch for {}",
            v.label
        );
    }
}
